import{_ as a,o as e,c as i,a2 as n}from"./chunks/framework.BZO4qERu.js";const g=JSON.parse('{"title":"Codex-to-IM 安装与使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/install-and-usage.md","filePath":"guide/install-and-usage.md","lastUpdated":1780511094000}'),t={name:"guide/install-and-usage.md"};function p(d,s,o,l,c,h){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="codex-to-im-安装与使用指南" tabindex="-1">Codex-to-IM 安装与使用指南 <a class="header-anchor" href="#codex-to-im-安装与使用指南" aria-label="Permalink to &quot;Codex-to-IM 安装与使用指南&quot;">​</a></h1><p>本文面向需要把本机 Codex 或 Claude Code 接到飞书里使用的用户。当前推荐路径是安装本地 <code>codex-to-im</code> 应用，运行安装向导完成机器人和默认 runtime 配置，然后在 IM 里通过命令绑定和继续本地线程。</p><h2 id="运行模型" tabindex="-1">运行模型 <a class="header-anchor" href="#运行模型" aria-label="Permalink to &quot;运行模型&quot;">​</a></h2><p>安装后推荐先运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>项目不接管 <code>~/.codex</code>、<code>~/.claude-code</code> 或 <code>~/.claude-code-router</code> 的模型供应商配置。Codex CLI、Claude Code 或本机登录态应按你的环境自行配置或安装；安装向导只写入 <code>~/.codex-to-im/config.v2.json</code> 和兼容快照 <code>config.env</code>。</p><h2 id="飞书应用配置" tabindex="-1">飞书应用配置 <a class="header-anchor" href="#飞书应用配置" aria-label="Permalink to &quot;飞书应用配置&quot;">​</a></h2><p>飞书侧需要至少完成以下配置：</p><ol><li>在飞书开放平台创建自建应用，记录 <code>App ID</code> 和 <code>App Secret</code>。</li><li>启用 Bot 能力。</li><li>添加消息发送、消息读取、卡片读写、消息更新、云文档评论写入等权限。</li><li>发布版本并由管理员审批。</li><li>启动 <code>codex-to-im</code> bridge。</li><li>在飞书应用的事件订阅里选择长连接，并添加 <code>im.message.receive_v1</code>、<code>drive.notice.comment_add_v1</code>、<code>im.chat.member.bot.deleted_v1</code>、<code>im.chat.disbanded_v1</code> 事件和 <code>card.action.trigger</code> 回调。</li><li>再次发布版本并审批。</li></ol><p>如果 <code>CTI_FEISHU_ALLOWED_USERS</code> 为空，所有能给机器人发消息的人都可以使用该 bot。需要收紧访问时，填写飞书用户 open_id 列表。</p><p>云文档评论能力除事件订阅外，还需要文档评论写入权限。缺少 <code>docs:document.comment:create</code> 或 <code>docs:document.comment:write_only</code> 时，bridge 可以收到 <code>drive.notice.comment_add_v1</code>，但写回评论或添加回复前的 <code>Typing</code> 表情会收到 Feishu <code>99991672</code> 权限错误。</p><h2 id="本地工作台" tabindex="-1">本地工作台 <a class="header-anchor" href="#本地工作台" aria-label="Permalink to &quot;本地工作台&quot;">​</a></h2><p>常用命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> url</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre></div><p>工作台主要用于：</p><ul><li>查看 UI 和 bridge 是否运行。</li><li>配置飞书通道实例。</li><li>测试飞书凭据和连通性。</li><li>查看本地 Codex 会话和 Codex-to-IM Bridge 会话。</li><li>查看会话历史。</li><li>给通道设置默认目标会话。</li><li>查看日志和诊断信息。</li></ul><p>配置主文件是 <code>~/.codex-to-im/config.v2.json</code>。<code>config.env</code> 仍可作为初始配置和运维快照使用；程序启动时会把旧格式迁移或同步到 v2 配置。</p><h2 id="im-中的基础使用" tabindex="-1">IM 中的基础使用 <a class="header-anchor" href="#im-中的基础使用" aria-label="Permalink to &quot;IM 中的基础使用&quot;">​</a></h2><p>把机器人拉进飞书会话或直接私聊机器人后，可以使用以下流程：</p><ol><li>发送 <code>/status</code> 检查 bridge 和通道状态。</li><li>发送 <code>/t</code> 查看最近 10 条本地 Codex 线程。</li><li>发送 <code>/t all</code> 查看最多 200 条本地 Codex 线程。</li><li>发送 <code>/t 1</code> 切换当前 IM 会话到第 1 条线程。</li><li>之后直接发送普通消息，即可继续该 Codex 线程。</li></ol><p>新建会话：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/new</span></span>
<span class="line"><span>/new my-thread</span></span>
<span class="line"><span>/new my-thread ./my-project</span></span>
<span class="line"><span>/clear</span></span>
<span class="line"><span>/clear my-thread ./my-project</span></span></code></pre></div><p>切换和重命名：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/t 1</span></span>
<span class="line"><span>/t archive 1</span></span>
<span class="line"><span>/t rename new-name</span></span></code></pre></div><p>查看历史：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/his</span></span>
<span class="line"><span>/his 10</span></span>
<span class="line"><span>/his raw 10</span></span>
<span class="line"><span>/his json</span></span></code></pre></div><p>调整运行设置：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/provider sdk</span></span>
<span class="line"><span>/provider pty</span></span>
<span class="line"><span>/provider tmux</span></span>
<span class="line"><span>/mode normal</span></span>
<span class="line"><span>/mode yolo</span></span>
<span class="line"><span>/reasoning 5</span></span>
<span class="line"><span>/model</span></span>
<span class="line"><span>/model &lt;模型名&gt;</span></span></code></pre></div><p>停止当前任务：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/stop</span></span></code></pre></div><p>发送以 <code>/</code> 开头的普通文本时，在前面多加一个 <code>/</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>//status</span></span></code></pre></div><p>这会把 <code>/status</code> 作为普通消息发给 Codex，而不是执行命令。</p><h2 id="提供方选择" tabindex="-1">提供方选择 <a class="header-anchor" href="#提供方选择" aria-label="Permalink to &quot;提供方选择&quot;">​</a></h2><p>在 Codex runtime 下，默认推荐 <code>sdk</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/provider sdk</span></span></code></pre></div><p><code>sdk</code> 使用 <code>@openai/codex-sdk</code> 直接运行 Codex turn，适合大多数 IM 远程对话。Codex 还支持 <code>pty</code> 和 <code>tmux</code>。</p><p>需要通过 Codex TUI 运行，但不需要手动 attach 终端时，可以使用 <code>pty</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/provider pty</span></span>
<span class="line"><span>/pty-screen</span></span>
<span class="line"><span>/pty-screen 120 5s</span></span>
<span class="line"><span>/pty-screen stop</span></span></code></pre></div><p><code>pty</code> 会用伪终端启动 Codex TUI 并 resume 当前 Codex thread。Codex TUI 首次询问是否信任当前目录时，bridge 会把确认请求转发到 IM，只有用户选择信任后才会继续发送本轮 prompt。</p><p>需要接管已有终端或 TUI，并保留可 attach 的 tmux session 时，可以使用 <code>tmux</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/provider tmux</span></span>
<span class="line"><span>/tmux-switch</span></span>
<span class="line"><span>/tmux-attach &lt;session&gt;</span></span>
<span class="line"><span>/tmux-screen</span></span>
<span class="line"><span>/tmux ...你的输入...</span></span></code></pre></div><p><code>tmux</code> 模式依赖本机 tmux session，适合把一个已经打开的终端会话映射到 IM。</p><p>在 Claude runtime 下，<code>/provider</code> 切换的是 Claude provider：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/runtime claude</span></span>
<span class="line"><span>/provider pty</span></span>
<span class="line"><span>/provider sdk</span></span></code></pre></div><p><code>pty</code> 使用本机 Claude Code TUI/JSONL mirror 路径，适合 CCR-backed Claude Code 和需要观察 TUI 的场景；<code>sdk</code> 使用 <code>@anthropic-ai/claude-agent-sdk</code> 原生事件路径。</p><h2 id="数据和日志" tabindex="-1">数据和日志 <a class="header-anchor" href="#数据和日志" aria-label="Permalink to &quot;数据和日志&quot;">​</a></h2><p>Codex-to-IM 自有数据位于：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codex-to-im</span></span></code></pre></div><p>常见文件：</p><ul><li><code>config.v2.json</code>：结构化配置。</li><li><code>config.env</code>：兼容旧工具的配置快照。</li><li><code>data/sessions.json</code>：Bridge 会话。</li><li><code>data/channel-chats.json</code>：IM chat 到 Bridge 会话的绑定；一个 Bridge 会话只绑定一个聊天。</li><li><code>data/messages/</code>：Bridge 消息缓存。</li><li><code>logs/</code>：bridge、UI 和启动器日志。</li><li><code>runtime/</code>：运行状态、PID、端口等临时状态。</li></ul><p>Codex 自己的会话数据仍由 Codex 管理，Codex-to-IM 只读取：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codex/sessions/**/*.jsonl</span></span>
<span class="line"><span>~/.codex/state_*.sqlite</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="codex-to-im-open-后-bridge-启动失败" tabindex="-1"><code>codex-to-im open</code> 后 bridge 启动失败 <a class="header-anchor" href="#codex-to-im-open-后-bridge-启动失败" aria-label="Permalink to &quot;\`codex-to-im open\` 后 bridge 启动失败&quot;">​</a></h3><p>先查看：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>再打开工作台日志页，确认飞书凭据、Codex 登录态和本机 Node.js 版本。</p><h3 id="飞书收不到消息" tabindex="-1">飞书收不到消息 <a class="header-anchor" href="#飞书收不到消息" aria-label="Permalink to &quot;飞书收不到消息&quot;">​</a></h3><p>检查：</p><ul><li>飞书应用是否已发布并审批。</li><li>Bot 能力是否已启用。</li><li>长连接事件订阅是否保存成功。</li><li><code>im.message.receive_v1</code>、<code>drive.notice.comment_add_v1</code>、<code>im.chat.member.bot.deleted_v1</code>、<code>im.chat.disbanded_v1</code> 和 <code>card.action.trigger</code> 是否已添加。</li><li>云文档评论回复是否缺少 <code>docs:document.comment:create</code> 或 <code>docs:document.comment:write_only</code> 权限。</li><li>bridge 是否正在运行。</li></ul><h3 id="流式卡片没有逐字输出" tabindex="-1">流式卡片没有逐字输出 <a class="header-anchor" href="#流式卡片没有逐字输出" aria-label="Permalink to &quot;流式卡片没有逐字输出&quot;">​</a></h3><p>这是正常情况。当前 Codex SDK 事件通常在 assistant 消息完成时给出最终文本，飞书流式卡片主要用于展示 thinking、工具进度和最终答案更新。</p><h3 id="限制使用者" tabindex="-1">限制使用者 <a class="header-anchor" href="#限制使用者" aria-label="Permalink to &quot;限制使用者&quot;">​</a></h3><p>默认 <code>CTI_FEISHU_ALLOWED_USERS=</code> 为空，表示不做用户白名单限制。要限制用户，设置为飞书 open_id 列表：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CTI_FEISHU_ALLOWED_USERS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ou_xxx,ou_yyy</span></span></code></pre></div><p>修改后重启 bridge：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open</span></span></code></pre></div><h3 id="卸载" tabindex="-1">卸载 <a class="header-anchor" href="#卸载" aria-label="Permalink to &quot;卸载&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex-to-im</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unlink</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex-to-im</span></span></code></pre></div><p>如需清理本地数据，再删除：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex-to-im</span></span></code></pre></div>`,72)])])}const u=a(t,[["render",p]]);export{g as __pageData,u as default};
